module shift_reg_parallel_load (
    input wire [7:0] d,
    input wire clk,
    input wire load,
    output reg [7:0] q
);

  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge dbg_halt) begin
    if (load)
        q <= d;
    else
        q <= {q[6:0], 1'b0};
end

endmodule
